// ──────────────────────────────────────────────────────────────────────
// Process Articles
// 1. Pull each feed separately so per-feed quotas can be enforced.
// 2. Within each feed: sort by date desc, drop stale (>24h) and URL dupes.
// 3. Round-robin across feeds so no single topic drowns the others.
// 4. Title-similarity dedup (Jaccard ≥ 0.6) catches the same story
//    appearing under different URLs from different publishers.
// ──────────────────────────────────────────────────────────────────────

var FEEDS = [
  { node: 'RSS - Ukraine War',         topic: 'ukraine'    },
  { node: 'RSS - World Politics',      topic: 'world'      },
  { node: 'RSS - Tech & Programming',  topic: 'tech'       },
  { node: 'RSS - AI',                  topic: 'ai'         },
  { node: 'RSS - Sports',              topic: 'sports'     },
  { node: 'RSS - Running',             topic: 'running'    },
  { node: 'RSS - Speedcubing',         topic: 'speedcubing'},
  { node: 'RSS - Science',             topic: 'science'    },
  { node: 'RSS - Space',               topic: 'space'      },
  { node: 'RSS - Trending',            topic: 'trending'   }
];

var PER_FEED_CAP = 5;
var TOTAL_CAP    = 50;
var SIM_THRESH   = 0.6;
var STALE_HOURS  = 24;

var STOPWORDS = {a:1,an:1,the:1,of:1,in:1,on:1,at:1,to:1,for:1,with:1,and:1,or:1,but:1,is:1,are:1,was:1,were:1,be:1,been:1,has:1,have:1,had:1,will:1,says:1,said:1,after:1,before:1,as:1,by:1,from:1,how:1,why:1,what:1,when:1,who:1,its:1,this:1,that:1,not:1,new:1};

function tokenize(title) {
  return (title || '').toLowerCase()
    .replace(/^(live|watch|video|update|breaking|exclusive|opinion|analysis)[:\s-]+/i, '')
    .replace(/[^a-z0-9\s]/g, ' ')
    .split(/\s+/)
    .filter(function (w) { return w.length > 2 && !STOPWORDS[w]; });
}

function toSet(tokens) {
  var s = {};
  for (var i = 0; i < tokens.length; i++) s[tokens[i]] = 1;
  return s;
}

function jaccard(setA, setB) {
  var keysA = Object.keys(setA);
  var keysB = Object.keys(setB);
  if (keysA.length === 0 || keysB.length === 0) return 0;
  var inter = 0;
  for (var k = 0; k < keysA.length; k++) if (setB[keysA[k]]) inter++;
  return inter / (keysA.length + keysB.length - inter);
}

function extractSource(d) {
  if (d.source) {
    if (typeof d.source === 'string') return d.source;
    if (d.source._) return d.source._;
    if (d.source.$ && d.source.$.url) return d.source.$.url;
  }
  var m = (d.title || '').match(/ - ([^-]+)$/);
  return m ? m[1].trim() : 'News';
}

var cutoff = new Date(Date.now() - STALE_HOURS * 60 * 60 * 1000);

// Phase 1 — collect candidates per feed, sorted newest first, capped
var perFeed = [];
for (var f = 0; f < FEEDS.length; f++) {
  var feed = FEEDS[f];
  var rawItems;
  try { rawItems = $(feed.node).all(); } catch (e) { rawItems = []; }

  var sorted = rawItems
    .map(function (it) { return it.json; })
    .sort(function (a, b) {
      var da = new Date(a.isoDate || a.pubDate || 0).getTime();
      var db = new Date(b.isoDate || b.pubDate || 0).getTime();
      return db - da;
    });

  var kept = [];
  for (var i = 0; i < sorted.length && kept.length < PER_FEED_CAP; i++) {
    var d = sorted[i];
    var url = d.link || d.guid || '';
    if (!url) continue;
    var pubDate = d.isoDate ? new Date(d.isoDate) : d.pubDate ? new Date(d.pubDate) : new Date();
    if (pubDate < cutoff) continue;

    var cleanTitle = (d.title || 'Untitled').replace(/ - [^-]+$/, '').substring(0, 300);
    kept.push({
      url: url,
      pubDate: pubDate,
      cleanTitle: cleanTitle,
      tokens: tokenize(cleanTitle),
      raw: d,
      feedTopic: feed.topic
    });
  }
  perFeed.push(kept);
}

// Phase 2 — round-robin merge with global URL + title-similarity dedup
var seenUrls = {};
var keptSets = [];
var result = [];

for (var rank = 0; rank < PER_FEED_CAP && result.length < TOTAL_CAP; rank++) {
  for (var fi = 0; fi < perFeed.length && result.length < TOTAL_CAP; fi++) {
    var c = perFeed[fi][rank];
    if (!c) continue;
    if (seenUrls[c.url]) continue;

    var newSet = toSet(c.tokens);
    var dup = false;
    for (var t = 0; t < keptSets.length; t++) {
      if (jaccard(keptSets[t], newSet) >= SIM_THRESH) { dup = true; break; }
    }
    if (dup) continue;

    seenUrls[c.url] = true;
    keptSets.push(newSet);

    var description = (c.raw.contentSnippet || c.raw.content || c.raw.summary || c.raw.description || '')
      .replace(/<[^>]*>/g, '')
      .substring(0, 600);

    result.push({
      json: {
        title: c.cleanTitle,
        url: c.url,
        description: description,
        source: extractSource(c.raw),
        feedTopic: c.feedTopic,
        published_at: c.pubDate.toISOString()
      }
    });
  }
}

return result;

var groqResponse = $json;
var article = $("Prepare Groq Request").item.json;

var content = (groqResponse && groqResponse.choices && groqResponse.choices[0] && groqResponse.choices[0].message) ? groqResponse.choices[0].message.content : "{}";

var ai;
try {
  var cleaned = content.replace(/```json\n?|```\n?/g, "").trim();
  ai = JSON.parse(cleaned);
} catch (e) {
  return null;
}

var score = parseInt(ai.score);
if (!score || score < 1 || score > 10) return null;

var topics = Array.isArray(ai.topics) ? ai.topics.slice(0, 6) : [];
if (article.feedTopic && topics.indexOf(article.feedTopic) === -1) {
  topics.unshift(article.feedTopic);
}

return {
  json: {
    title: article.title,
    url: article.url,
    source: article.source,
    published_at: article.published_at,
    summary: (ai.summary || "").substring(0, 500),
    score: score,
    topics: topics.slice(0, 6)
  }
};
